import { connection } from 'next/server'

/**
 * Displays the current server timestamp on each request.
 *
 * Uses `connection()` to opt out of static prerendering at the component
 * level — the most targeted approach, rather than making the entire route
 * dynamic with `force-dynamic` or `revalidate = 0`.
 *
 * `connection()` is a request-lifecycle signal that tells Next.js this
 * component cannot be statically prerendered, so it runs on every request.
 */
export async function ServerTimestamp() {
  // Signal to Next.js that this component is dynamic (not statically rendered).
  // This is the recommended approach when you need dynamic data without using
  // cookies() or headers() for the opt-out.
  await connection()

  const now = new Date()
  const timestamp = now.toISOString()
  const localeString = now.toLocaleString('en-US', {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    timeZoneName: 'long',
  })

  return (
    <div className="timestamp-card">
      <div className="timestamp-label">Server Timestamp</div>
      <time dateTime={timestamp} className="timestamp-iso">
        {timestamp}
      </time>
      <div className="timestamp-formatted">{localeString}</div>
    </div>
  )
}

