import { Suspense } from 'react'
import { ServerTimestamp } from './server-timestamp'

function TimestampFallback() {
  return <div className="timestamp-card">Loading timestamp…</div>
}

export default function Home() {
  return (
    <main>
      <h1>Server Timestamp</h1>
      <p>This timestamp is generated on <strong>every request</strong> — it is <em>not</em> prerendered at build time.</p>
      <Suspense fallback={<TimestampFallback />}>
        <ServerTimestamp />
      </Suspense>
      <p className="note">
        Refresh the page to see the timestamp update.
      </p>
    </main>
  )
}

