* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen,
    Ubuntu, Cantarell, sans-serif;
  background: #0f172a;
  color: #e2e8f0;
  min-height: 100vh;
  display: flex;
  justify-content: center;
  padding: 3rem 1rem;
}

main {
  text-align: center;
  max-width: 480px;
}

h1 {
  font-size: 2rem;
  font-weight: 700;
  margin-bottom: 0.5rem;
  background: linear-gradient(135deg, #60a5fa, #a78bfa);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

p {
  font-size: 0.95rem;
  color: #94a3b8;
  margin-bottom: 2rem;
  line-height: 1.5;
}

p.note {
  margin-top: 2rem;
  font-size: 0.85rem;
  color: #64748b;
}

.timestamp-card {
  background: #1e293b;
  border: 1px solid #334155;
  border-radius: 12px;
  padding: 2rem;
  display: inline-flex;
  flex-direction: column;
  gap: 0.75rem;
  min-width: 320px;
}

.timestamp-label {
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: #60a5fa;
}

.timestamp-iso {
  font-family: 'SF Mono', 'Fira Code', 'Cascadia Code', monospace;
  font-size: 1.1rem;
  color: #f1f5f9;
  word-break: break-all;
}

.timestamp-formatted {
  font-size: 0.85rem;
  color: #94a3b8;
}

